import pytest
import requests

def test_create_observation_valid_loinc_code(auth_headers, patient_id, base_url):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {
            "coding": [{
                "system": "http://loinc.org",
                "code": "8867-4",
                "display": "Heart rate"
            }]
        },
        "subject": {"reference": f"Patient/{patient_id}"},
        "valueQuantity": {
            "value": 72,
            "unit": "beats/min",
            "system": "http://unitsofmeasure.org",
            "code": "/min"
        }
    }
    resp = requests.post(
        f"{base_url}/Observation",
        json=payload,
        headers=auth_headers
    )
    obs_id = resp.json().get("id")
    try:
        assert resp.status_code == 201
        body = resp.json()
        assert body["resourceType"] == "Observation"
        assert obs_id
        assert body["code"]["coding"][0]["system"] == "http://loinc.org"
        assert body["code"]["coding"][0]["code"] == "8867-4"
    finally:
        if obs_id:
            requests.delete(f"{base_url}/Observation/{obs_id}", headers=auth_headers)

