import requests

def test_create_observation_boundary_large_numeric_value(
    auth_headers, patient_id, base_url
):
    large_value = 9999999.99
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {
            "coding": [{
                "system": "http://loinc.org",
                "code": "2339-0",
                "display": "Glucose"
            }]
        },
        "subject": {"reference": f"Patient/{patient_id}"},
        "effectiveDateTime": "2024-12-31T23:59:59.999+00:00",
        "valueQuantity": {
            "value": large_value,
            "unit": "mg/dL",
            "system": "http://unitsofmeasure.org",
            "code": "mg/dL"
        }
    }
    resp = requests.post(
        f"{base_url}/Observation",
        json=payload,
        headers=auth_headers
    )
    obs_id = resp.json().get("id")
    try:
        assert resp.status_code == 201
        body = resp.json()
        assert abs(body["valueQuantity"]["value"] - large_value) < 0.01
    finally:
        if obs_id:
            requests.delete(f"{base_url}/Observation/{obs_id}", headers=auth_headers)
